import { Component } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Task } from '../../models/task.model';

import { TaskFormComponent } from '../task-form/task-form.component';

@Component({
  selector: 'app-task-list',
  standalone: true,
  imports: [CommonModule, TaskFormComponent], 
  templateUrl: './task-list.component.html',
  styleUrls: ['./task-list.component.css']
})
export class TaskListComponent {
  tasks: Task[] = [
    { id: 1, title: 'Configurar base de datos', description: 'Instalar PostgreSQL y crear esquemas.', status: 'pending' },
    { id: 2, title: 'Crear API', description: 'Armar los endpoints con Flask.', status: 'in-progress' },
    { id: 3, title: 'Diseñar mockups', description: 'Hacer el diseño en Figma.', status: 'completed' }
  ];

  getTasksByStatus(status: 'pending' | 'in-progress' | 'completed'): Task[] {
    return this.tasks.filter(task => task.status === status);
  }

  changeStatus(task: Task, newStatus: 'pending' | 'in-progress' | 'completed') {
    task.status = newStatus;
  }

  deleteTask(id: number | undefined) {
    if (id) {
      this.tasks = this.tasks.filter(task => task.id !== id);
    }
  }

  onTaskAdded(newTask: Task) {
    this.tasks.push(newTask);
  }
}
